import React, { useState, useEffect } from "react";
import menkesLogo from "../../images/menkeslogo.webp";
import solmarLogo from "../../images/solmarlogo.webp";
import tributeLogo from "../../images/tributelogo.png";

const metrics = [
  {
    k: "10+",
    label: "Years on enterprise sites",
    body: "Hands-on experience as a Site Superintendent on high-rise residential and mixed-use developments.",
  },
  {
    k: "$50M+",
    label: "Cumulative project budgets",
    body: "Direct oversight of multi-million dollar scopes from foundation through deficiency closeout.",
  },
  {
    k: "On-Time",
    label: "Timeline & logistics",
    body: "Critical-path scheduling, trade coordination, and city inspection handling honed at scale.",
  },
];

// --- THE ANIMATED COUNTER COMPONENT ---
const AnimatedCounter = ({ text, delayMs }) => {
  const [count, setCount] = useState(0);
  const [hasStarted, setHasStarted] = useState(false);

  // This magic Regex splits "$50M+" into Prefix("$"), Number("50"), Suffix("M+")
  const match = text.match(/^(\D*)(\d+)(\D*)$/);

  useEffect(() => {
    // If the text is a word like "On-Time", abort the animation and just show the word
    if (!match) return;

    const target = parseInt(match[2], 10);
    const duration = 2000; // 2 seconds of counting
    let startTimestamp = null;

    // Wait for the requested delay so the page can load first
    const timer = setTimeout(() => {
      setHasStarted(true);

      const step = (timestamp) => {
        if (!startTimestamp) startTimestamp = timestamp;
        const progress = Math.min((timestamp - startTimestamp) / duration, 1);

        // easeOutExpo math for that premium "fast start, slow finish" agency feel
        const easeOut = progress === 1 ? 1 : 1 - Math.pow(2, -10 * progress);

        setCount(Math.floor(easeOut * target));

        if (progress < 1) {
          window.requestAnimationFrame(step);
        }
      };
      window.requestAnimationFrame(step);
    }, delayMs);

    return () => clearTimeout(timer);
  }, [text, delayMs]);

  // If it's not a number, just render the normal text
  if (!match) return <>{text}</>;

  return (
    <>
      {match[1]}
      {hasStarted ? count : 0}
      {match[3]}
    </>
  );
};
// ------------------------------------

export default function Experience() {
  return (
    <section
      id="experience"
      data-testid="experience-section"
      className="bg-white py-28 md:py-40"
    >
      <div className="max-w-7xl mx-auto px-6 md:px-10">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 lg:gap-20">

          <div className="lg:col-span-5 reveal">
            <div className="flex items-center gap-3 mb-6">
              <span className="block w-10 h-px bg-brand-accent" />
              <span className="text-xs tracking-[0.28em] uppercase text-brand-smoke font-medium">
                Our Roots
              </span>
            </div>
            <h2
              data-testid="experience-headline"
              className="font-display text-4xl md:text-5xl lg:text-6xl font-medium text-brand-ink tracking-tighter leading-[1.05]"
            >
              An enterprise pedigree, brought home.
            </h2>
            <p className="mt-8 text-lg leading-relaxed text-brand-smoke max-w-md">
              Sunwest Builds was founded on a decade of work for Canada&apos;s most rigorous developers.
              That same discipline now lives inside every residential project we
              touch.
            </p>

            {/* HIGH-END LOGO TRUST BAR */}
            <div className="mt-12 md:mt-16" data-testid="experience-developers">
              <div className="text-xs tracking-[0.28em] uppercase text-brand-muted font-medium mb-6">
                Background with
              </div>
              {/* flex-nowrap forces a single row, shrink ensures they scale down if needed */}
              <div className="flex flex-nowrap items-center justify-between gap-4 md:gap-6 w-full pr-4">
                <img
                  src={menkesLogo}
                  alt="Menkes Developments"
                  className="h-6 md:h-8 w-auto max-w-[30%] object-contain grayscale opacity-45 hover:grayscale-0 hover:opacity-100 transition-all duration-500 shrink"
                />

                <img
                  src={solmarLogo}
                  alt="Solmar Developments"
                  className="h-10 md:h-14 w-auto max-w-[30%] object-contain grayscale opacity-45 hover:grayscale-0 hover:opacity-100 transition-all duration-500 shrink"
                />

                <img
                  src={tributeLogo}
                  alt="Tribute Communities"
                  className="h-6 md:h-8 w-auto max-w-[30%] object-contain grayscale opacity-45 hover:grayscale-0 hover:opacity-100 transition-all duration-500 shrink"
                />
              </div>
            </div>
          </div>

          <div className="lg:col-span-7 grid grid-cols-1 sm:grid-cols-3 gap-px bg-brand-line">
            {metrics.map((m, i) => (
              <div
                key={m.label}
                data-testid={`experience-metric-${i}`}
                className="reveal bg-white p-8 md:p-10 flex flex-col justify-between min-h-[260px]"
              >
                <div>
                  <span className="font-display text-5xl md:text-6xl font-medium text-brand-ink tracking-tighter">
                    {/* The animation is wired up right here! */}
                    <AnimatedCounter text={m.k} delayMs={800} />
                  </span>
                  <div className="mt-3 text-sm uppercase tracking-widest text-brand-muted">
                    {m.label}
                  </div>
                </div>
                <p className="mt-8 text-sm leading-relaxed text-brand-smoke">
                  {m.body}
                </p>
              </div>
            ))}
          </div>

        </div>
      </div>
    </section>
  );
}
